export default PlaceCity







function searchState(o,q){
  let rrs = {}
  _Util.ObjectKeys(o).map(k=>{
    if(q){
      let qLw = q.toLowerCase();
      let nLw = k && k.toLowerCase();
      if(qLw && nLw && nLw.indexOf(qLw)>=0){
        rrs[k] = {"name":k};
      }
    }
    else{
      rrs[k] = {"name":k};
    }
  })
  return rrs;
} 




function searchCity(o,q){
  let rrs = {}
  _Util.ObjectKeys(o).map(k=>{
    if(q){
      let qLw = q.toLowerCase();
      let nLw = o[k]["city"] && o[k]["city"].toLowerCase();
      if(qLw && nLw && nLw.indexOf(qLw)>=0){
        rrs[k] = {"name": o[k]["city"] , id:k };
      }
    }
    else{
      rrs[k] = {"name": o[k]["city"] , id:k };
    }
  })
  return rrs;
} 


